#include <stdio.h>
int v[51];
int main(){
    int n, i, aux, f, cn, s, s2;
    s=s2=0;
    scanf("%d", &n);
    cn=n/2;
    for(i=0; i<cn; i++)
      scanf("%d", &v[i]);
    f=0;
    while(f==0){
      f=1;
      for(i=0; i<cn-1; i++)
        if(v[i]>v[i+1]){
          aux=v[i];
          v[i]=v[i+1];
          v[i+1]=aux;
          f=0;
        }
    }
    for(i=1; i<=n; i+=2)
      s=s+abs(v[(i-1)/2]-i);
    for(i=2; i<=n; i+=2)
      s2=s2+abs(v[(i-2)/2]-i);
    if(s>s2)
      printf("%d", s2);
    else
      printf("%d", s);
    return 0;
}

