// A. Chess Placing http://codeforces.com/contest/985/problem/A

fn main() {
    let stdin = std::io::stdin();
    let mut buf = String::new();
    stdin.read_line(&mut buf).unwrap(); // discard
    buf.clear();
    stdin.read_line(&mut buf).unwrap();
    let mut arr: Vec<i32> = buf.split_whitespace()
        .map(|s| s.parse().unwrap())
        .collect();
    arr[..].sort_unstable();
    let f = |mut m: i32| {
        let mut total = 0;
        for n in &arr {
            total += (n - m).abs();
            m += 2;
        }
        total
    };
    let ans: i32 = vec![1, 2].into_iter().map(f).min().unwrap();
    println!("{}", ans);
}
